insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('sport-studies:5-2-3-technology-and-the-spectator-experience:misc:ff016115', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For a longer question on this topic, naming one positive effect of technology is enough to answer it well.</p><p><strong>✅ The correct idea:</strong> Naming one effect only ever earns a fraction of the marks. Section B and C questions expect BOTH a positive and a negative effect, applied to the scenario, and Section C additionally wants a final judgement about which matters more. A single named effect caps the answer in the lowest band.</p>", "question": "For a Section C ''Discuss'' question on this topic, naming one positive effect alone will...?", "options": ["Always earn full marks, because one clearly named effect is all that is ever required", "Cap the answer in the lowest band, since both sides and a judgement are expected", "Automatically move the answer into the top band without needing anything else", "Disqualify the whole answer completely, scoring zero marks under any circumstances"]}'::jsonb, '{"answer": 1, "explain": "Discuss/Evaluate questions need both sides plus a judgement; one named effect on its own caps the answer in the basic band, though it is not disqualified outright."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:misc:600fe42d', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A long video review doesn''t really matter to the crowd because it only takes a minute or so.</p><p><strong>✅ The correct idea:</strong> Even a short delay is credited as a genuine negative effect, because it interrupts the atmosphere and pace the crowd had built up. Mark schemes reward students who explain WHY the wait matters (broken tension, quietened crowd), not just that a wait happened.</p>", "question": "Why does a mark scheme credit ''a long wait for a decision'' as a genuine negative effect?", "options": ["Because waiting always causes every single official''s original decision to be reversed", "Because a wait of any length is against the official rules of every sport", "Because even a short delay can break the crowd''s atmosphere and interrupt the pace", "Because waiting removes any further need for spectators to hold a valid ticket"]}'::jsonb, '{"answer": 2, "explain": "The genuine negative is the interruption to atmosphere and pace, however brief the wait feels — it is not about rule-breaking, guaranteed reversals, or tickets."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:misc:185ecb78', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Every stadium and every sport should use as much review technology as possible, since more technology is always better.</p><p><strong>✅ The correct idea:</strong> The exam rewards the opposite idea: suitability. A review is only worth having if its benefit (accuracy, fan understanding) justifies its cost and the delay it causes for that particular fixture. A small local match may not need — or be able to afford — the same technology as a major televised final.</p>", "question": "Why is ''more technology is always better'' a misconception on this topic?", "options": ["Because suitability means weighing a review''s benefit against its real cost and delay", "Because technology has never once been shown to help any spectator understand a decision", "Because every governing body has permanently banned technology from all major events", "Because spectators are legally forbidden from watching any form of screen replay"]}'::jsonb, '{"answer": 0, "explain": "The correct idea is suitability — balancing benefit against cost and delay — not that technology never helps, is banned, or that replays are forbidden."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:tips:23a0e86a', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Questions on the spectator experience are usually applied or evaluative. Match your answer to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name an effect. \"Identify one positive effect of technology on spectators [1]\" = one clear effect, nothing more.</li>\n<li><strong>Explain</strong> — give a reason. \"Explain how technology could reduce a spectator''s experience\" = an effect <em>plus</em> why it reduces the experience.</li>\n<li><strong>Discuss / Evaluate</strong> — weigh BOTH sides (positive and negative) and reach a judgement about which matters more, using the scenario.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1]–[2] wants brief points; higher-mark Section B questions want points applied to the scenario; the 8-mark Section C question always wants both sides plus a judgement.</p>", "question": "A question says: ''Discuss whether technology has improved the spectator experience [8]''. What earns the top band?", "options": ["Naming a single positive effect and stopping the answer there", "Listing as many effects as possible with no explanation of any of them", "Describing your own personal favourite piece of sports technology in far greater detail than needed", "A balanced look at both positive and negative effects, ending in a justified judgement"]}'::jsonb, '{"answer": 3, "explain": "The top band needs balance across both sides plus a judgement — a single effect, a bare list, or a personal favourite would all be capped much lower."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:tips:33b7b277', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'tips', 'mcq', 1, '{"readingTitle": "tip — Balance is everything — both sides, then a judgement", "reading": "<p>The most common way to lose marks on this topic is writing about only positives, or only negatives. Build your answer as <strong>positive → negative → judgement</strong>:</p>\n<ul>\n<li><strong>❌ weak:</strong> \"Technology is good because it shows replays.\" (one-sided, no negative, no judgement.)</li>\n<li><strong>✅ strong:</strong> \"Big screen replays help fans understand decisions, but the wait for a review can break the atmosphere. Overall, the benefit to understanding probably outweighs the loss of atmosphere for a big decision.\"</li>\n</ul>\n<p>Also weigh <strong>suitability</strong>: not every fixture needs, or can afford, the same level of technology as a major final.</p>", "question": "Why should you weigh up the ''suitability'' of technology in a longer answer on this topic?", "options": ["It shows you understand that not every fixture needs or can justify the same technology", "It proves that every single possible piece of technology should be used at every single match", "It removes any requirement to mention a single negative effect in your answer", "It replaces the need to reach any final judgement at the end of your answer"]}'::jsonb, '{"answer": 0, "explain": "Suitability shows deeper understanding — that the right amount of technology depends on the event — it does not mean ''use everything'', skip negatives, or avoid a judgement."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:tips:2d3badd4', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> quick recall of positive/negative effects appears in <strong>Section A</strong>. Applied questions about a named stadium, club or event appear in <strong>Section B</strong>. The balanced 8-mark <strong>Discuss/Evaluate</strong> question in <strong>Section C</strong> often asks whether technology has \"improved\" the spectator experience overall.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Always pair a positive with a genuine negative — examiners reward balance, not a one-sided list.</li>\n<li>Use the scenario''s own details (the stadium, the club, the ticket price) rather than a generic example.</li>\n<li>Finish with a judgement that says WHICH matters more and WHY, not just \"it depends\".</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One positive effect of technology here is… because…\"</li>\n<li>\"However, a negative effect is… because…\"</li>\n<li>\"Overall, I think technology has/has not improved the experience because…\"</li>\n</ul>", "question": "Why is finishing a longer answer with a clear judgement important?", "options": ["Because a judgement lets you avoid mentioning any negative effects at all", "Because a judgement is only ever needed in Section A multiple-choice questions", "Because it shows which effect matters more and why, not just that both exist", "Because examiners only read the very first sentence of any longer answer"]}'::jsonb, '{"answer": 2, "explain": "A judgement shows you can weigh the effects and decide which matters more and why — simply listing both sides without deciding is not enough for the top band."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:fib:e400f25b', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'fib', 'fib', 1, '{"question": "Big screens let fans see the same _____ the officials used to reach a decision.", "blankOptions": {"B1": ["suitability", "prices", "statistics", "evidence"]}}'::jsonb, '{"blanks": {"B1": "evidence"}}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:fib:7b281bd4', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'fib', 'fib', 1, '{"question": "Broadcast graphics and _____ help home viewers understand the contest in more depth.", "blankOptions": {"B1": ["suitability", "prices", "statistics", "atmosphere"]}}'::jsonb, '{"blanks": {"B1": "statistics"}}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:fib:3c229611', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'fib', 'fib', 1, '{"question": "A long wait for a video review can break the _____ inside the stadium.", "blankOptions": {"B1": ["suitability", "statistics", "evidence", "atmosphere"]}}'::jsonb, '{"blanks": {"B1": "atmosphere"}}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:fib:ab63ca07', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'fib', 'fib', 1, '{"question": "Installing and running review technology is expensive, which can raise ticket or subscription _____.", "blankOptions": {"B1": ["suitability", "prices", "atmosphere", "statistics"]}}'::jsonb, '{"blanks": {"B1": "prices"}}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:fib:c6037bb4', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'fib', 'fib', 1, '{"question": "Judging whether a review is worth its cost and delay for a fixture is about the _____ of the technology.", "blankOptions": {"B1": ["prices", "suitability", "statistics", "atmosphere"]}}'::jsonb, '{"blanks": {"B1": "suitability"}}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:match:42c8a6ba', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Big screen replay”?", "options": ["The crowd''s noise, tension and excitement, which a long technology-based delay can interrupt", "A system that turns a fast or hard-to-see moment into a clear graphic for viewers", "Stadium footage of a technology-based decision that lets fans see the evidence and understand a call", "Weighing whether a review is worth its cost and delay for that sport, venue or decision"]}'::jsonb, '{"answer": 2, "explain": "“Big screen replay” means: Stadium footage of a technology-based decision that lets fans see the evidence and understand a call"}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:match:ac57f836', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Broadcast graphics”?", "options": ["Watching a replay so closely that you miss the next live action happening in front of you", "On-screen statistics and detail added for people watching at home, deepening their understanding", "A system that turns a fast or hard-to-see moment into a clear graphic for viewers", "The crowd''s noise, tension and excitement, which a long technology-based delay can interrupt"]}'::jsonb, '{"answer": 1, "explain": "“Broadcast graphics” means: On-screen statistics and detail added for people watching at home, deepening their understanding"}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:match:99518c28', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Ball-tracking technology”?", "options": ["On-screen statistics and detail added for people watching at home, deepening their understanding", "A system that turns a fast or hard-to-see moment into a clear graphic for viewers", "The crowd''s noise, tension and excitement, which a long technology-based delay can interrupt", "Weighing whether a review is worth its cost and delay for that sport, venue or decision"]}'::jsonb, '{"answer": 1, "explain": "“Ball-tracking technology” means: A system that turns a fast or hard-to-see moment into a clear graphic for viewers"}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:match:8172a724', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Atmosphere”?", "options": ["A system that turns a fast or hard-to-see moment into a clear graphic for viewers", "The crowd''s noise, tension and excitement, which a long technology-based delay can interrupt", "Watching a replay so closely that you miss the next live action happening in front of you", "Weighing whether a review is worth its cost and delay for that sport, venue or decision"]}'::jsonb, '{"answer": 1, "explain": "“Atmosphere” means: The crowd''s noise, tension and excitement, which a long technology-based delay can interrupt"}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:match:abf138b9', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Over-reliance on screens”?", "options": ["The crowd''s noise, tension and excitement, which a long technology-based delay can interrupt", "Stadium footage of a technology-based decision that lets fans see the evidence and understand a call", "A system that turns a fast or hard-to-see moment into a clear graphic for viewers", "Watching a replay so closely that you miss the next live action happening in front of you"]}'::jsonb, '{"answer": 3, "explain": "“Over-reliance on screens” means: Watching a replay so closely that you miss the next live action happening in front of you"}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:match:0420fd82', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Suitability of technology”?", "options": ["The crowd''s noise, tension and excitement, which a long technology-based delay can interrupt", "Stadium footage of a technology-based decision that lets fans see the evidence and understand a call", "Weighing whether a review is worth its cost and delay for that sport, venue or decision", "On-screen statistics and detail added for people watching at home, deepening their understanding"]}'::jsonb, '{"answer": 2, "explain": "“Suitability of technology” means: Weighing whether a review is worth its cost and delay for that sport, venue or decision"}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:exam:f853b13a', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'exam', 'mcq', 1, '{"num": "2", "question": "Which command word asks you to simply name something, with no explanation required?", "options": ["Explain — you must give a reason for the point", "Identify or State — you name it, with no reason needed", "Discuss — you must weigh up both sides of an issue", "Evaluate — you must reach a justified overall judgement"], "hint": "Think about which word needs no reason and no judgement at all — just a name.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Identify or State.</strong></p>\n<ul>\n<li>Identify/State only requires naming something — no reason (Explain) and no judgement (Discuss/Evaluate).</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:mcq:04d9a991', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'mcq', 'mcq', 1, '{"question": "How many marks is the whole R184 exam paper worth, and how long do you have to complete it?", "options": ["70 marks, to be completed in 1 hour and 15 minutes", "100 marks, to be completed in 2 hours and 30 minutes", "50 marks, to be completed in 45 minutes flat", "60 marks, to be completed in 1 hour and 30 minutes"]}'::jsonb, '{"answer": 0, "explain": "R184 is 70 marks in 1 hour 15 minutes. The other totals and times do not match the real paper."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:mcq:f24d72b7', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'mcq', 'mcq', 1, '{"question": "Which of these correctly matches a section of the R184 paper to its marks and features?", "options": ["Section B is worth 28 marks and is always built around a scenario", "Section A is worth 30 marks and is always built around a scenario", "Section C is worth 12 marks and is entirely multiple choice with no writing", "Section A is worth 12 marks and is always built around a scenario"]}'::jsonb, '{"answer": 0, "explain": "Section B is 28 marks and scenario-based. Section A is 30 marks but is mostly short recall, not scenario-based; Section C is not entirely multiple choice."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:mcq:41fc1e24', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'mcq', 'mcq', 1, '{"question": "A Section C question says: ''Evaluate whether the legacy of hosting a major event outweighs its cost.'' Which command word tells you to reach a justified judgement?", "options": ["Evaluate — because it specifically asks for a weighed, justified judgement", "Discuss — because it specifically asks for a weighed, justified judgement instead", "Identify — because naming the legacy is all that is required here", "Describe — because explaining what a legacy means is all that is required"]}'::jsonb, '{"answer": 0, "explain": "Evaluate demands a justified judgement. Discuss only asks you to weigh both sides without necessarily reaching one; Identify and Describe don''t ask for judgement at all."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:mcq:f5c5061d', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'mcq', 'mcq', 1, '{"question": "A Section A question is worth [1] mark. What is the safest way to answer it?", "options": ["Give one short point, with no further explanation needed", "Write a fully developed paragraph explaining every possible reason", "Present both sides of the issue before reaching a judgement", "Leave the answer blank until you reach the higher-mark questions"]}'::jsonb, '{"answer": 0, "explain": "A [1]-mark question wants one clear point. A full paragraph, a both-sides discussion, or leaving it blank all waste marks or time."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:mcq:45e0146b', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'mcq', 'mcq', 1, '{"question": "Which pair correctly matches a command word to what it demands?", "options": ["Describe: say what something is or what happens", "State: weigh up both sides and reach a justified conclusion", "Explain: give a reason, often using the word because", "Discuss: simply name something with no further detail at all"]}'::jsonb, '{"answer": 2, "explain": "Explain = point plus reason (because). State actually means ''just name it''; Discuss actually means ''weigh both sides'' — this option has swapped their real meanings."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:mcq:a9c2e9e1', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'mcq', 'mcq', 1, '{"question": "A Section B question is worth [4] marks and gives you a named scenario. What does this tariff most likely require?", "options": ["One single unexplained fact, worth all four marks alone", "Points applied to the given scenario, not just generic knowledge", "Both sides of an argument, fully weighed, ending in an overall judgement", "A multiple-choice letter chosen with no further working shown"]}'::jsonb, '{"answer": 1, "explain": "A [4]-mark Section B question wants points applied to the scenario. The full both-sides-plus-judgement shape belongs to a [6]/[8] levelled question, not a [4]-marker."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:tf:cef2806f', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'tf', 'tf', 1, '{"question": "The R184 exam paper is worth 70 marks and lasts 1 hour 15 minutes."}'::jsonb, '{"answer": true, "explain": "That''s the real total — 70 marks in 1 hour 15 minutes, across three sections."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:tf:5c8daa0c', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'tf', 'tf', 1, '{"question": "Section A contains only multiple-choice questions and nothing else."}'::jsonb, '{"answer": false, "explain": "Section A also has shorter written answers and one longer, levelled 8-mark question — it isn''t all MCQ."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:tf:1b2794ca', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'tf', 'tf', 1, '{"question": "Sections B and C are both built around a scenario or context you are given."}'::jsonb, '{"answer": true, "explain": "Both sections give you a named scenario your answer must use, and both require analysis and evaluation."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:tf:35320364', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'tf', 'tf', 1, '{"question": "''Identify'' and ''Evaluate'' ask you for exactly the same kind of answer."}'::jsonb, '{"answer": false, "explain": "Identify wants a bare name; Evaluate wants both sides weighed plus a justified judgement — very different demands."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:tf:dc157315', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'tf', 'tf', 1, '{"question": "A [1]-mark question is best answered with a single, short point."}'::jsonb, '{"answer": true, "explain": "One clear point secures the one available mark; anything longer just spends time you need elsewhere."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:tf:bb36df87', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'tf', 'tf', 1, '{"question": "Writing far more than a question''s mark tariff calls for always earns extra credit."}'::jsonb, '{"answer": false, "explain": "Marks are capped at the tariff, so extra length beyond what is needed earns nothing extra and wastes time."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:learn:67485dc3', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'learn', 'mcq', 1, '{"readingTitle": "The R184 paper: three sections, one clock", "reading": "<h4>The shape of the exam</h4>\n<ul>\n<li>Unit R184 \"Contemporary issues in sport\" is assessed by a single <strong>written exam paper</strong>, worth <strong>70 marks</strong> in total, to be completed in <strong>1 hour 15 minutes</strong>.</li>\n<li>It is a <strong>terminal</strong> assessment — it must be sat in your final exam series, unlike the coursework units.</li>\n<li>The paper is split into <strong>three sections</strong>. Whatever the topic area, every section keeps testing the same skill: applying your knowledge and weighing things up, not just reciting facts.</li>\n</ul>\n<h4>Section A — 30 marks</h4>\n<ul>\n<li>Mostly short recall: multiple-choice questions and shorter written answers (1–4 marks each).</li>\n<li>Section A also contains <strong>one longer, levelled question</strong> (worth 8 marks) that still needs a balanced, judged answer.</li>\n</ul>\n<h4>Section B — 28 marks</h4>\n<ul>\n<li>Built around a <strong>context or scenario</strong> you are given — a named leisure centre, event, sport or performer that your answer must use.</li>\n<li>Mostly short-and-medium written answers, including <strong>levelled 6-mark questions</strong>.</li>\n</ul>\n<h4>Section C — 12 marks</h4>\n<ul>\n<li>Also scenario-based, and built mainly around an <strong>extended response</strong>, including an <strong>8-mark \"Discuss\" or \"Evaluate\"</strong> question.</li>\n<li>Sections B and C always require analysis and evaluation — you cannot pass them by listing facts alone.</li>\n</ul>", "question": "Which of these correctly describes the R184 exam paper?", "options": ["70 marks in total, completed in 1 hour 15 minutes, split into three sections", "100 marks in total, completed in 2 hours, split into two sections", "50 marks in total, completed in 45 minutes, with no written answers at all", "70 marks in total, completed in 1 hour 15 minutes, made up only of multiple-choice questions"]}'::jsonb, '{"answer": 0, "explain": "The paper is 70 marks in 1 hour 15 minutes, across three sections (A/B/C) — not two, and not multiple-choice only."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:learn:fcf0d153', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'learn', 'mcq', 1, '{"readingTitle": "Command words: what the exam is really asking for", "reading": "<h4>Same-looking questions, very different demands</h4>\n<ul>\n<li><strong>Identify / State</strong> — just name it. No explanation, no reason, no extra detail. One clear point usually earns one mark.</li>\n<li><strong>Describe</strong> — say what something is or what happens. More than naming it, but you are not yet giving a reason <em>why</em>.</li>\n<li><strong>Explain</strong> — give a reason. A safe habit is using the word <em>\"because\"</em> somewhere, linking a point to its cause or effect.</li>\n<li><strong>Discuss</strong> — present <strong>both sides</strong> of an issue. You do not have to pick a winner, but you must show understanding of more than one side.</li>\n<li><strong>Evaluate</strong> — go one step further than Discuss: weigh up both sides <em>and</em> reach a <strong>justified judgement</strong> about which matters most, or whether something is worth it overall.</li>\n</ul>\n<h4>Why the difference matters</h4>\n<ul>\n<li>Writing an \"Explain\" style answer when the command word is \"State\" wastes time you need elsewhere on the paper.</li>\n<li>Writing a one-sided answer when the command word is \"Discuss\" or \"Evaluate\" caps your mark in a lower band, however well written that one side is.</li>\n</ul>", "question": "Which command word specifically asks you to reach a justified judgement, not just present both sides?", "options": ["Describe", "Evaluate", "Identify", "State"]}'::jsonb, '{"answer": 1, "explain": "Evaluate is the command word that demands a justified judgement; Discuss stops at weighing both sides; Identify/State/Describe don''t ask for any judgement."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:learn:e17efff7', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'learn', 'mcq', 1, '{"readingTitle": "Reading the mark tariff to size your answer", "reading": "<h4>The number in the brackets is an instruction</h4>\n<ul>\n<li><strong>[1]</strong> — one point is enough. Writing three sentences to earn one mark steals time from later questions.</li>\n<li><strong>[2]</strong> — usually two separate points, or one point that is properly developed.</li>\n<li><strong>[4]</strong> — in Section B, this is usually points <strong>applied</strong> to the scenario you are given, not generic knowledge recited from memory. Two applied points, each worth two marks, is a common shape.</li>\n<li><strong>[6] / [8]</strong> — a <strong>levelled</strong> question. The mark scheme is banded, not a checklist: reaching the top band needs both sides of the issue <strong>and</strong> a justified judgement, applied to any scenario given.</li>\n</ul>\n<h4>Tariff mismatches are the easiest marks to lose</h4>\n<ul>\n<li>A single unexplained word for an 8-mark question loses almost all the marks available, however correct that word is.</li>\n<li>A three-page answer to a 1-mark question still earns exactly one mark — the extra time spent writing it is wasted.</li>\n<li>Before you write, glance at the command word and the mark tariff together — they tell you the shape of answer the examiner expects.</li>\n</ul>", "question": "A question is worth [4] marks and is set in Section B, using a named scenario. What does this tariff most likely require?", "options": ["One single fact, stated with no further detail at all", "Points that are applied to the given scenario, not just generic knowledge", "Both sides of the argument fully weighed, ending in a justified judgement", "A single multiple-choice letter chosen with no working shown at all"]}'::jsonb, '{"answer": 1, "explain": "A [4]-mark Section B question usually wants points applied to the scenario — the full both-sides-plus-judgement shape belongs to a [6]/[8] levelled question instead."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:learn:332e1881', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'learn', 'mcq', 1, '{"readingTitle": "Putting it together across the whole R184 spec", "reading": "<h4>The skill is the same wherever the content changes</h4>\n<ul>\n<li>Command words and tariffs work exactly the same way whichever topic area a question is drawn from — participation, values, PEDs, hosting events, NGBs or technology.</li>\n<li><strong>\"Identify two user groups\" [2]</strong> — two names, nothing more.</li>\n<li><strong>\"Explain why a performer might use a PED\" [2]</strong> — a reason, using \"because\", not just naming a PED.</li>\n<li><strong>\"Describe how technology can support match officials\" [2]</strong> — say what the technology does (for example, checking a close decision), not why it matters.</li>\n</ul>\n<h4>Two more examples: a Governing Body, and technology for spectators</h4>\n<ul>\n<li><strong>\"State two responsibilities of a named National Governing Body\" [2]</strong> — just name two, from rules and discipline, coaching, safety or funding. No explanation needed.</li>\n<li><strong>\"Evaluate whether increased use of technology has been good for spectators\" [8]</strong> — this needs both the positives (big screens, instant replays) and the negatives (cost, a slower flow of the game), ending in a justified overall view.</li>\n<li>Whatever the topic, ask yourself the same two questions before you write: <em>What does this command word want? What does this mark tariff give me time for?</em></li>\n</ul>", "question": "A question reads: ''Evaluate whether increased use of technology has been good for spectators.'' [8] What must a top-band answer include?", "options": ["Only the positive effects of technology on spectators, described in full detail with no negatives mentioned at all", "Both positive and negative effects on spectators, ending in a justified judgement", "A single named piece of technology, identified with no further comment", "Two separate user groups who might attend the event, simply named"]}'::jsonb, '{"answer": 1, "explain": "An 8-mark Evaluate question needs balance (both sides) plus a justified judgement — one-sided detail, a bare name, or an unrelated user-group list all miss what the command word demands."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:misc:733dcf68', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If I write more for a 1-mark question, I can''t lose marks, so it''s safer to explain fully.</p><p><strong>✅ The correct idea:</strong> Marks are capped at the tariff — a 1-mark question gives exactly 1 mark for a correct point, however much you write around it. The real cost is TIME: minutes spent over-explaining a 1-mark answer are minutes you don''t have left for a 6- or 8-mark question later in the paper.</p>", "question": "Why is writing a long explanation for a 1-mark question a mistake?", "options": ["Because it cannot earn more than the 1 mark available, and wastes time needed elsewhere", "Because examiners deduct marks for writing any extra detail beyond what a question specifically asks for", "Because 1-mark questions never actually appear on the real R184 paper", "Because long answers are always factually incorrect by definition"]}'::jsonb, '{"answer": 0, "explain": "A 1-mark question is capped at 1 mark regardless of length — the real loss is the time taken away from higher-mark questions."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:misc:df01c854', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''Discuss'' means giving only the side of the argument I personally agree with, as long as I explain it well.</p><p><strong>✅ The correct idea:</strong> ''Discuss'' specifically means presenting BOTH sides, even if you personally think one is stronger. A brilliantly explained one-sided answer is capped in a lower band, because the mark scheme rewards balance before it rewards depth.</p>", "question": "A student writes only the positive effects of hosting a major event for a ''Discuss'' question. What happens to their mark?", "options": ["It automatically scores full marks if the writing quality is excellent", "It is capped in a lower band, because Discuss requires both sides", "It scores zero, because one-sided answers are never credited at all", "It is marked the same as a 1-mark ''State'' question regardless of length"]}'::jsonb, '{"answer": 1, "explain": "A one-sided Discuss answer still earns some credit but is capped in a lower band — full marks need balance, not just polish."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:misc:801adaf7', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Section B and Section C are basically the same, so it doesn''t matter which one I''m answering.</p><p><strong>✅ The correct idea:</strong> They share the ''scenario-based'' feature, but carry different marks and demands: Section B is 28 marks of short-and-medium answers including 6-mark levelled questions; Section C is 12 marks built mainly around one 8-mark Discuss/Evaluate extended response. Knowing which section you are in helps you judge how much to write.</p>", "question": "What is a genuine difference between Section B and Section C?", "options": ["Section B is 28 marks of short/medium answers; Section C is 12 marks centred on one extended response", "Section B never uses a scenario, but Section C always does", "Section C is worth more marks overall than both Section A and Section B combined, according to this claim", "Section B contains no written answers of any kind, only multiple choice"]}'::jsonb, '{"answer": 0, "explain": "Section B (28 marks, short/medium) and Section C (12 marks, one extended response) both use a scenario but differ in marks and shape."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:misc:a0f2926a', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The number of marks tells me how many separate facts to list — 8 marks means I should list 8 facts.</p><p><strong>✅ The correct idea:</strong> A high tariff on a levelled question (6 or 8 marks) is NOT ''one mark per fact''. It is marked in bands: a thorough, balanced, judged answer can reach the top band with far fewer than 8 separate facts, while 8 disconnected facts with no balance or judgement stays stuck in a low band.</p>", "question": "For an 8-mark ''Evaluate'' question, what actually reaches the top band?", "options": ["Listing exactly eight separate facts, regardless of whether they connect to each other", "A balanced answer covering both sides plus a justified judgement", "Naming eight different named examples with no further comment at all", "Repeating the same single point in eight slightly different sentences"]}'::jsonb, '{"answer": 1, "explain": "Levelled questions are marked by band, not by fact-count — balance plus a justified judgement is what reaches the top band."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:tips:dc6eb453', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this page — matching length to demand", "reading": "<p>Every R184 question opens with a command word. Match your answer''s length and shape to it, not to the space left on the page:</p>\n<ul>\n<li><strong>Identify / State</strong> — one short point. Nothing more, however tempting.</li>\n<li><strong>Describe</strong> — say what it is or what happens; still no reason needed yet.</li>\n<li><strong>Explain</strong> — give a reason. A safe habit: use the word \"because\" somewhere.</li>\n<li><strong>Discuss / Evaluate</strong> — both sides, and for Evaluate, a justified judgement too.</li>\n</ul>\n<p><strong>Check the tariff too:</strong> [1] = one point; [4] = applied points; [6]/[8] = levelled and banded — never a simple checklist.</p>", "question": "A question says: ''Describe two ways technology supports match officials [2]''. What does ''Describe'' need here?", "options": ["Simply naming two pieces of technology, with no further detail at all", "Saying what each piece of technology does, not just naming it", "Explaining why officials need this kind of support in the first place", "Weighing up whether technology is good or bad for officiating overall"]}'::jsonb, '{"answer": 1, "explain": "Describe wants what the technology does — naming it alone (Identify) or explaining why/weighing it up (Explain/Evaluate) are different command words."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:tips:6174b2cc', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule for Section B and C: use the scenario", "reading": "<p>Sections B and C always give you a scenario — a named leisure centre, event, sport or performer. The most common way to lose marks here is writing a generally-true answer that ignores it.</p>\n<ul>\n<li><strong>❌ generic:</strong> \"Hosting events can bring investment.\"</li>\n<li><strong>✅ applied:</strong> \"Hosting the event described brings investment, because the scenario mentions new transport links being built for it.\"</li>\n</ul>\n<p>Build applied answers as <strong>point → scenario detail → effect</strong>, whichever topic area the scenario is drawn from.</p>", "question": "In a Section B or C scenario question, where should your example come from?", "options": ["Any sport you personally follow, regardless of the scenario given", "The scenario you have actually been given in the question", "A generic textbook example that could apply to any scenario", "The mark scheme from a completely different exam paper"]}'::jsonb, '{"answer": 1, "explain": "Sections B and C are applied — marks are for using the given scenario. A generic example that ignores it is capped."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:tips:fb6e822e', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this shows up + sentence starters for the levelled questions", "reading": "<p><strong>Where the skill is tested:</strong> command-word discipline matters in every section, but the biggest marks ride on the levelled questions — one 8-marker in Section A, 6-markers in Section B, and the 8-mark Discuss/Evaluate that anchors Section C.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Before writing anything, underline the command word and circle the mark tariff.</li>\n<li>For a levelled question, jot down both sides first — it stops your answer drifting one-sided.</li>\n<li>Finish every Discuss/Evaluate with one judgement sentence, even a short one — it is often worth real marks.</li>\n</ul>\n<p><strong>Sentence starters:</strong></p>\n<ul>\n<li>\"One argument in favour is… because…\"</li>\n<li>\"On the other hand… because…\"</li>\n<li>\"Overall, the most significant point is… because…\"</li>\n</ul>", "question": "Why is finishing a Discuss/Evaluate answer with a judgement sentence worthwhile?", "options": ["It fills space at the end of the answer with no real benefit at all", "It is often where real marks sit, especially for Evaluate questions", "It replaces the need to give both sides of the argument beforehand", "It is only ever relevant for a 1-mark ''State'' question"]}'::jsonb, '{"answer": 1, "explain": "A justified concluding judgement is often exactly what separates a mid-band answer from a top-band one, especially for Evaluate."}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:fib:0c789b49', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'fib', 'fib', 1, '{"question": "The whole R184 exam paper is worth _____ marks in total.", "blankOptions": {"B1": ["B", "70", "75", "Identify"]}}'::jsonb, '{"blanks": {"B1": "70"}}'::jsonb),
