('sport-studies:6-1-command-words-and-exam-sections:fib:5c182d99', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'fib', 'fib', 1, '{"question": "Section _____ is worth 28 marks and is always built around a scenario.", "blankOptions": {"B1": ["Evaluate", "B", "75", "Identify"]}}'::jsonb, '{"blanks": {"B1": "B"}}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:fib:301ce64b', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'fib', 'fib', 1, '{"question": "Section _____ is worth 12 marks and includes an 8-mark Discuss or Evaluate question.", "blankOptions": {"B1": ["75", "B", "C", "70"]}}'::jsonb, '{"blanks": {"B1": "C"}}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:fib:a8df17a5', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'fib', 'fib', 1, '{"question": "The command word that asks you to just name something, with no explanation, is _____ (or State).", "blankOptions": {"B1": ["Evaluate", "Identify", "C", "75"]}}'::jsonb, '{"blanks": {"B1": "Identify"}}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:fib:823ab4a8', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'fib', 'fib', 1, '{"question": "The command word that asks you to weigh up both sides AND reach a justified judgement is _____.", "blankOptions": {"B1": ["C", "70", "75", "Evaluate"]}}'::jsonb, '{"blanks": {"B1": "Evaluate"}}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:match:5e4ff3f9', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Section A”?", "options": ["Command word asking you to simply name something, with no explanation needed", "Worth 28 marks; scenario-based short and medium answers, including levelled 6-mark questions", "Worth 30 marks; mostly short recall including MCQs, plus one longer levelled question", "Command word asking you to say what something is or what happens"]}'::jsonb, '{"answer": 2, "explain": "“Section A” means: Worth 30 marks; mostly short recall including MCQs, plus one longer levelled question"}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:match:02db8d1d', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Section B”?", "options": ["Command word asking you to give a reason, often using the word because", "Worth 28 marks; scenario-based short and medium answers, including levelled 6-mark questions", "Command word asking you to say what something is or what happens", "Command word asking you to present and weigh up both sides of an issue"]}'::jsonb, '{"answer": 1, "explain": "“Section B” means: Worth 28 marks; scenario-based short and medium answers, including levelled 6-mark questions"}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:match:a6bdb117', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Section C”?", "options": ["Worth 12 marks; scenario-based extended response, including an 8-mark Discuss or Evaluate question", "Worth 28 marks; scenario-based short and medium answers, including levelled 6-mark questions", "Command word asking you to give a reason, often using the word because", "Command word asking you to simply name something, with no explanation needed"]}'::jsonb, '{"answer": 0, "explain": "“Section C” means: Worth 12 marks; scenario-based extended response, including an 8-mark Discuss or Evaluate question"}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:match:4dbb1f97', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Identify / State”?", "options": ["Command word asking you to simply name something, with no explanation needed", "Command word asking you to say what something is or what happens", "Worth 30 marks; mostly short recall including MCQs, plus one longer levelled question", "Command word asking you to present and weigh up both sides of an issue"]}'::jsonb, '{"answer": 0, "explain": "“Identify / State” means: Command word asking you to simply name something, with no explanation needed"}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:match:39765f01', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Describe”?", "options": ["Worth 28 marks; scenario-based short and medium answers, including levelled 6-mark questions", "Command word asking you to say what something is or what happens", "Command word asking you to present and weigh up both sides of an issue", "Worth 30 marks; mostly short recall including MCQs, plus one longer levelled question"]}'::jsonb, '{"answer": 1, "explain": "“Describe” means: Command word asking you to say what something is or what happens"}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:match:39d5bd39', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Explain”?", "options": ["Command word asking you to simply name something, with no explanation needed", "Command word asking you to present and weigh up both sides of an issue", "Command word asking you to say what something is or what happens", "Command word asking you to give a reason, often using the word because"]}'::jsonb, '{"answer": 3, "explain": "“Explain” means: Command word asking you to give a reason, often using the word because"}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:match:56aeb14e', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Discuss”?", "options": ["Command word asking you to present and weigh up both sides of an issue", "Command word asking you to simply name something, with no explanation needed", "Command word asking you to weigh up both sides and reach a justified judgement", "Command word asking you to give a reason, often using the word because"]}'::jsonb, '{"answer": 0, "explain": "“Discuss” means: Command word asking you to present and weigh up both sides of an issue"}'::jsonb),
('sport-studies:6-1-command-words-and-exam-sections:match:468230c7', 'sport-studies', 'sport-studies:6-1-command-words-and-exam-sections', '6.1 Command Words and Exam Sections', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Evaluate”?", "options": ["Command word asking you to say what something is or what happens", "Command word asking you to present and weigh up both sides of an issue", "Worth 12 marks; scenario-based extended response, including an 8-mark Discuss or Evaluate question", "Command word asking you to weigh up both sides and reach a justified judgement"]}'::jsonb, '{"answer": 3, "explain": "“Evaluate” means: Command word asking you to weigh up both sides and reach a justified judgement"}'::jsonb),
('sport-studies:6-2-extended-response-technique:exam:b28f49bb', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'exam', 'mcq', 1, '{"num": "2", "question": "Which command word most directly requires you to weigh up both sides of an issue and reach a supported decision?", "options": ["Identify — simply name a relevant point, with no further detail required at all", "Describe — give a straightforward account of a feature, without giving any reasons", "Evaluate — weigh up both sides of the issue and reach a justified decision", "State — give a short, factual answer without any explanation attached to it"], "hint": "Think about which command word points most directly at the final step of the 3-step method — the judgement.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — Evaluate.</strong></p>\n<ul>\n<li>Evaluate points most directly at reaching a supported decision, though Discuss questions are marked the same way.</li>\n<li>Identify, Describe and State are all lower-tariff command words that do not require a judgement.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:6-2-extended-response-technique:mcq:b091d003', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'mcq', 'mcq', 1, '{"question": "Which of these best describes what a justified judgement adds to a levelled answer?", "options": ["A decision about which side matters more, or what it depends on, with a reason", "A restatement of the points already made, written in slightly different words", "An extra fact about the topic that has not been mentioned anywhere before", "A promise that the student has checked their spelling and punctuation carefully"]}'::jsonb, '{"answer": 0, "explain": "A judgement decides something and gives a reason drawn from the analysis — restating points, adding an unrelated fact, or mentioning spelling does not count as one."}'::jsonb),
('sport-studies:6-2-extended-response-technique:mcq:984cd111', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'mcq', 'mcq', 1, '{"question": "A Band 2 answer applies one side well but never covers the opposite side. What single change is most likely to move it towards Band 3?", "options": ["Making the one side that is already covered even longer and more detailed than before", "Adding a developed point on the other side, then a reasoned judgement", "Repeating the same point using different, more advanced vocabulary", "Removing the link to the scenario so the answer reads more generally"]}'::jsonb, '{"answer": 1, "explain": "Band 3 needs balance and a judgement. Lengthening one side, repeating a point, or removing the scenario link does not add the missing balance."}'::jsonb),
('sport-studies:6-2-extended-response-technique:mcq:2d8f59b4', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'mcq', 'mcq', 1, '{"question": "Which sentence below is an example of ''just listing'' rather than analysis?", "options": ["Technology helps officials. It also helps spectators. It is used in lots of sports.", "Technology helps officials review close calls, which reduces errors in the final result.", "Technology gives an advantage to teams that can afford the most advanced equipment.", "Technology can slow the game down, which may reduce enjoyment for some spectators."]}'::jsonb, '{"answer": 0, "explain": "The first option states three separate facts with no ''so what?'' development. The others each explain an effect, which is what analysis needs."}'::jsonb),
('sport-studies:6-2-extended-response-technique:mcq:f1444e07', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'mcq', 'mcq', 1, '{"question": "In a Section B or C scenario question, where should your supporting example come from?", "options": ["Any sport you personally follow, regardless of what the question describes", "The scenario or case study printed on the question paper itself", "The most famous athlete you can remember from any competition", "A general example that could apply to almost any similar question"]}'::jsonb, '{"answer": 1, "explain": "Application marks are for using the scenario given, not a general or personal example — even a well-written general point is capped if it ignores the case study."}'::jsonb),
('sport-studies:6-2-extended-response-technique:mcq:ebfbdd16', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'mcq', 'mcq', 1, '{"question": "Why does a one-sided answer stay capped in Band 2, even if that one side is detailed and well explained?", "options": ["Because Band 3 needs the discussion to cover both sides before a judgement", "Because detailed answers are always penalised for going into too much depth", "Because only Section C questions are ever marked using bands at all", "Because one-sided answers are usually far too short to reach any band"]}'::jsonb, '{"answer": 0, "explain": "Depth on one side is not the same as balance. Band 3 specifically requires both sides to be covered, however well one side alone is written."}'::jsonb),
('sport-studies:6-2-extended-response-technique:mcq:1a3c3811', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'mcq', 'mcq', 1, '{"question": "A student writes: ''So overall, there are advantages and disadvantages to hosting a major event.'' Why does this fail to earn full judgement marks?", "options": ["It mentions the specific name of the event, which should never appear anywhere in a conclusion", "It restates that both sides exist instead of deciding which matters more, and why", "It is placed at the end of the answer instead of somewhere in the middle", "It does not use the word ''overall'' in the correct grammatical position"]}'::jsonb, '{"answer": 1, "explain": "That sentence only confirms both sides exist — a real judgement names which side is stronger (or what it depends on) and gives a reason for that call."}'::jsonb),
('sport-studies:6-2-extended-response-technique:tf:cd54a42d', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'tf', 'tf', 1, '{"question": "A Band 3 answer must cover both sides of the issue, not just the side you find easiest."}'::jsonb, '{"answer": true, "explain": "Balance is one of the two things (with a reasoned judgement) that separates Band 3 from Band 2."}'::jsonb),
('sport-studies:6-2-extended-response-technique:tf:3daa0463', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'tf', 'tf', 1, '{"question": "As long as every sentence you write is a true fact, your answer is guaranteed to reach Band 3."}'::jsonb, '{"answer": false, "explain": "A list of true, undeveloped facts stays in Band 1 — marks come from developing points and reaching a judgement, not from accuracy alone."}'::jsonb),
('sport-studies:6-2-extended-response-technique:tf:ba93a6ef', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'tf', 'tf', 1, '{"question": "A conclusion that only restates that ''there are advantages and disadvantages'' is the same as a justified judgement."}'::jsonb, '{"answer": false, "explain": "That sentence is a summary. A real judgement decides which side matters more, or what it depends on, and gives a reason."}'::jsonb),
('sport-studies:6-2-extended-response-technique:tf:63eae95a', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'tf', 'tf', 1, '{"question": "In a Section B or C scenario question, your supporting example should come from the case study you were given."}'::jsonb, '{"answer": true, "explain": "Application marks reward using the scenario in front of you — a general example, however accurate, is capped."}'::jsonb),
('sport-studies:6-2-extended-response-technique:tf:5b04987c', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'tf', 'tf', 1, '{"question": "Moving from Band 2 to Band 3 usually means adding the other side of the argument and a reasoned judgement."}'::jsonb, '{"answer": true, "explain": "Those are the two changes most likely to lift a one-sided, applied answer into the top band."}'::jsonb),
('sport-studies:6-2-extended-response-technique:tf:68d0fef7', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'tf', 'tf', 1, '{"question": "A one-sided answer can still reach Band 3 as long as that one side is written in great detail."}'::jsonb, '{"answer": false, "explain": "Depth on one side does not replace balance. Band 3 specifically requires both sides to be covered before the judgement."}'::jsonb),
('sport-studies:6-2-extended-response-technique:learn:90182f63', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'learn', 'mcq', 1, '{"readingTitle": "The 3-step method for a top-band answer", "reading": "<h4>Why facts alone are not enough</h4>\n<ul>\n<li>\"Discuss\" and \"Evaluate\" questions are never marked on facts alone. A page of accurate points, with no thinking done to them, still lands near the bottom of the mark range.</li>\n<li>Build every levelled answer with the same three steps, in order.</li>\n</ul>\n<h4>Step 1 — Apply</h4>\n<ul>\n<li>Link your very first point to the scenario in front of you — a named event, place or situation — rather than a general point that could belong to any question.</li>\n</ul>\n<h4>Step 2 — Analyse both sides</h4>\n<ul>\n<li>For each point: state it, <strong>develop</strong> it (explain the effect), then ask <strong>\"so what?\"</strong> — what does this actually mean for the people or organisation in the scenario?</li>\n<li>Do this for <strong>one side</strong> of the issue, then do it again for the <strong>other side</strong>. Both sides must appear, or the analysis stays incomplete.</li>\n</ul>\n<h4>Step 3 — Reach a justified judgement</h4>\n<ul>\n<li>Finish by saying <strong>which side matters more</strong>, or <strong>what it depends on</strong> — and give a reason drawn from your own analysis, not a new, unexplained point.</li>\n<li>A judgement is a decision. A sentence that only restates your points is a summary, not a judgement, and does not earn the same credit.</li>\n</ul>", "question": "In the 3-step method, what is the main job of the ''analyse'' step?", "options": ["Weighing up both sides of the issue and explaining the effect of each point in turn", "Naming the scenario you were given, with no further comment added to it", "Copying out extra facts about the topic that were not actually asked for anywhere in the question", "Writing a one-line summary of the question before you start your answer"]}'::jsonb, '{"answer": 0, "explain": "Analysis means developing a point on each side and explaining its effect — naming the scenario is ''apply'', and copying facts or summarising the question skips analysis altogether."}'::jsonb),
('sport-studies:6-2-extended-response-technique:learn:428a346f', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'learn', 'mcq', 1, '{"readingTitle": "The band structure — what actually moves you up a band", "reading": "<h4>Three bands, one method</h4>\n<ul>\n<li><strong>Band 1 (basic, bottom marks):</strong> a short, one-sided answer that mostly lists points, with little or no link to the scenario.</li>\n<li><strong>Band 2 (reasonable, middle marks):</strong> sound understanding, applied to the scenario, with some analysis — but it may still lean to one side, or end without a judgement that is properly supported.</li>\n<li><strong>Band 3 (thorough, top marks):</strong> a balanced discussion of both sides, applied throughout, that reaches a judgement and explains why that judgement was reached.</li>\n</ul>\n<h4>The two things that lift Band 2 into Band 3</h4>\n<ul>\n<li><strong>Add the other side.</strong> A Band 2 answer often only explores one side well; adding a developed point on the opposite side is usually the single biggest gain available.</li>\n<li><strong>Add a reasoned judgement.</strong> Not \"overall, both are important\" — instead, name which matters more <em>in this scenario</em>, or what it depends on, and say why.</li>\n</ul>\n<h4>What band marks are NOT about</h4>\n<ul>\n<li>They are not about writing more words. A short, balanced, judged answer beats a long, one-sided list every time.</li>\n</ul>", "question": "A student''s answer explores one side well and applies it to the scenario, but never mentions the other side. Which band does this best fit?", "options": ["Band 1, because nothing at all in the answer is applied to the given scenario", "Band 3, because one side is thoroughly and fully explained in detail", "Band 2, because it is applied with some analysis but is not yet balanced", "No band, because an unbalanced answer earns zero marks regardless"]}'::jsonb, '{"answer": 2, "explain": "Applied, some analysis, but one-sided is the Band 2 pattern — Band 3 needs both sides plus a judgement, and an unbalanced answer still earns credit, just not full marks."}'::jsonb),
('sport-studies:6-2-extended-response-technique:learn:1fa81ccd', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'learn', 'mcq', 1, '{"readingTitle": "Sentence scaffolds for building the answer", "reading": "<p>Use a fixed set of starters so you never forget a step. Each starter has a job.</p>\n<h4>Starting a point (apply + develop)</h4>\n<ul>\n<li><strong>\"One reason [X] matters here is…\"</strong> — states the point and links it to the scenario.</li>\n<li><strong>\"This means that…\"</strong> — forces the \"so what?\" development the mark scheme rewards.</li>\n</ul>\n<h4>Moving to the other side</h4>\n<ul>\n<li><strong>\"On the other hand…\"</strong> — signals to the examiner (and to you) that you are now covering the opposite side, which is exactly what turns Band 2 into Band 3.</li>\n</ul>\n<h4>Reaching the judgement</h4>\n<ul>\n<li><strong>\"Overall, the most important [factor] is… because…\"</strong> — names a decision and gives a reason, rather than just restating both sides.</li>\n<li><strong>\"This depends on…\"</strong> — a valid judgement when the honest answer is \"it varies\", as long as you say what it varies with.</li>\n</ul>", "question": "Why does the starter ''On the other hand…'' matter so much in a levelled answer?", "options": ["It makes the answer noticeably longer without changing its content in any way", "It signals the switch to the second side of the argument, which balance needs", "It replaces the need to reach any final judgement at the end", "It is only useful in Section A multiple-choice questions"]}'::jsonb, '{"answer": 1, "explain": "''On the other hand'' marks the point where you bring in the opposite side — the exact move that lifts a one-sided Band 2 answer towards Band 3."}'::jsonb),
('sport-studies:6-2-extended-response-technique:learn:1a5f1139', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'learn', 'mcq', 1, '{"readingTitle": "Classic failings that cap your mark", "reading": "<h4>1. Being one-sided</h4>\n<ul>\n<li>Only exploring the side you find easiest caps you in Band 2, however well that one side is written.</li>\n</ul>\n<h4>2. Just listing</h4>\n<ul>\n<li><em>Weak:</em> \"Technology helps officials. It also helps spectators. It is used in many sports.\" Three true facts, zero development — this is a list, not analysis.</li>\n<li><em>Stronger:</em> \"Technology helps officials by reviewing close decisions, which means fewer errors reach the final result and the sport is seen as fairer.\"</li>\n</ul>\n<h4>3. A conclusion that only summarises</h4>\n<ul>\n<li><em>Weak:</em> \"So, in conclusion, there are advantages and disadvantages to this.\" That sentence makes no decision — it is a summary wearing a judgement''s clothing.</li>\n<li><em>Stronger:</em> \"Overall, the disadvantages matter more here because the cost involved would stop smaller clubs from ever using this technology.\"</li>\n</ul>\n<h4>4. Ignoring the scenario</h4>\n<ul>\n<li>A general point about \"sport\" instead of the named event, team or situation in front of you loses the application marks, even if the point itself is accurate.</li>\n</ul>", "question": "A student ends an answer with: ''So overall, there are good points and bad points to this.'' What is the main problem?", "options": ["It uses the word ''overall'', which examiners never want to see in an answer", "It is too short to be read by the examiner marking the paper", "It summarises rather than judging — it makes no decision or reasoned call", "It should have been written in the very first sentence of the answer instead"]}'::jsonb, '{"answer": 2, "explain": "A real judgement decides something and gives a reason. Restating that there are ''good and bad points'' is a summary, not a judgement, and does not earn top-band credit."}'::jsonb),
('sport-studies:6-2-extended-response-technique:misc:9e6676e3', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If I write lots of accurate facts about the topic, I should get full marks.</p><p><strong>✅ The correct idea:</strong> Accuracy is not the same as analysis. A list of true facts with no development (''technology helps officials, it also helps spectators, it is used in many sports'') stays in Band 1. Marks come from developing a point (''this means that…''), covering both sides, and reaching a judgement — not from the number of correct facts on the page.</p>", "question": "A student writes five accurate, undeveloped facts about a topic. Which band does this best match?", "options": ["Band 3, because every fact stated is completely accurate and true", "Band 1, because listing facts with no development shows little analysis", "No band, because only inaccurate answers are ever marked this particular way", "Band 2, because five facts is usually considered enough for that band"]}'::jsonb, '{"answer": 1, "explain": "Accuracy alone is a Band 1 pattern. Reaching Band 2 or 3 needs development, application and — for the top band — balance and a judgement."}'::jsonb),
('sport-studies:6-2-extended-response-technique:misc:3cfc7aec', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> I only need to explain one side of the argument really well to get full marks.</p><p><strong>✅ The correct idea:</strong> A single, well-developed side caps you in Band 2. Band 3 specifically asks for both sides — so plan two developed points, one for each side, before you reach your judgement. Depth on one side is valuable, but it cannot replace balance.</p>", "question": "Why can''t a very detailed, one-sided answer reach the top band?", "options": ["Because detailed answers are penalised for taking too long to mark", "Because the top band specifically requires both sides to be covered", "Because one-sided answers must always contain at least one factual error", "Because only short answers are ever placed into the top band"]}'::jsonb, '{"answer": 1, "explain": "The top band''s descriptor requires balance across both sides, on top of depth — so one side alone, however detailed, is capped below it."}'::jsonb),
('sport-studies:6-2-extended-response-technique:misc:7d96ceef', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> My conclusion just needs to sum up the points I already made.</p><p><strong>✅ The correct idea:</strong> A summary restates; a judgement decides. Compare: ''So there are advantages and disadvantages'' (summary — no decision) with ''Overall, the disadvantages matter more here because the cost would stop smaller clubs using it'' (judgement — a decision, with a reason). Only the second earns top-band credit.</p>", "question": "What is missing from the sentence ''So, overall, there are advantages and disadvantages to this''?", "options": ["It is missing a decision about which side matters more, and a reason why", "It is missing the specific word ''overall'', which has been left out completely", "It is missing a link to any user group affected by the topic", "It is missing a command word taken from the original question"]}'::jsonb, '{"answer": 0, "explain": "That sentence never decides anything — a judgement needs a call (which side, or what it depends on) plus a reason drawn from the analysis."}'::jsonb),
('sport-studies:6-2-extended-response-technique:misc:b6d3b0f1', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> I can use any example I like in a scenario question — it doesn''t need to come from the case study.</p><p><strong>✅ The correct idea:</strong> Section B and C questions give you a scenario so that you APPLY your knowledge to it. A general, unlinked example — even if accurate — loses the application marks. Always pull a name, place or detail from the case study into your first sentence on each point.</p>", "question": "A scenario question names a specific stadium and event. What should your example use?", "options": ["A completely different, unrelated event that the student prefers instead", "Details from the named stadium and event given in the scenario", "The most famous stadium in the world, regardless of the question", "No example at all, since Section B never asks for application"]}'::jsonb, '{"answer": 1, "explain": "Application marks reward using the scenario you were actually given — swapping in an unrelated example, however well known, does not earn them."}'::jsonb),
('sport-studies:6-2-extended-response-technique:tips:90675289', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'tips', 'mcq', 1, '{"readingTitle": "tip — Discuss vs Evaluate — what the marks actually demand", "reading": "<p>Both command words trigger the same 3-step method (apply → analyse both sides → judgement), but read the exact wording of the question before you start:</p>\n<ul>\n<li><strong>Discuss</strong> — weigh up the issue from more than one angle; a supported judgement is still expected at the top band.</li>\n<li><strong>Evaluate</strong> — the word itself points more directly at the final judgement, so make sure your last paragraph clearly states a decision, not just a summary.</li>\n</ul>\n<p><strong>Mark-count signal:</strong> 6 and 8 marks are always level-of-response (banded) — there is no fixed list of \"correct\" points, only bands describing HOW WELL you argue and judge.</p>", "question": "What do both ''Discuss'' and ''Evaluate'' questions have in common at the top band?", "options": ["Neither one ever requires you to mention the scenario given at all", "Both expect both sides to be covered and a judgement to be reached", "Both are always worth exactly one mark each on the paper", "Neither one is ever marked using bands or level descriptors"]}'::jsonb, '{"answer": 1, "explain": "Whichever command word is used, 6/8-mark answers are levelled, and the top band always needs balance plus a justified judgement."}'::jsonb),
('sport-studies:6-2-extended-response-technique:tips:5a701cd4', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where levelled questions appear + how to plan first", "reading": "<p><strong>Where they show up:</strong> Section A carries one 8-mark levelled question; Section B often includes a 6-mark levelled question inside a scenario; Section C''s extended response ends with an 8-mark Discuss/Evaluate.</p>\n<p><strong>Plan for 60 seconds before writing:</strong></p>\n<ul>\n<li>Jot ONE point for each side of the issue, linked to the scenario.</li>\n<li>Decide your judgement <em>before</em> you write the final paragraph, so your analysis builds towards it instead of surprising you at the end.</li>\n</ul>", "question": "Why is it useful to decide your judgement before writing the final paragraph?", "options": ["So the analysis in the middle of the answer can build towards it", "So you can avoid mentioning the scenario anywhere in your answer", "So the answer can be written without covering the opposite side at all", "So you never need to write a final paragraph at all"]}'::jsonb, '{"answer": 0, "explain": "Planning the judgement first means every earlier point can be chosen to support it, rather than bolting on a rushed decision at the end."}'::jsonb),
('sport-studies:6-2-extended-response-technique:tips:537a6a31', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'tips', 'mcq', 1, '{"readingTitle": "tip — Sentence starters + a worked mini-example", "reading": "<p><strong>Starters to reuse in any topic:</strong></p>\n<ul>\n<li>\"One reason [X] matters here is… This means that…\"</li>\n<li>\"On the other hand…\"</li>\n<li>\"Overall, the most important [factor] is… because…\"</li>\n</ul>\n<p><strong>Worked mini-example (technology in sport):</strong> \"One reason video review helps this event is that it corrects close refereeing decisions. This means that results are seen as fairer, which protects the competition''s reputation. On the other hand, reviewing decisions takes time, which can slow the game and frustrate spectators watching live. Overall, fairness matters more here because a wrong result damages trust in the sport for far longer than a short delay is remembered.\"</p>", "question": "In the worked mini-example, which phrase signals the move to the opposing side?", "options": ["\"One reason… matters here\"", "\"This means that…\"", "\"On the other hand…\"", "\"Overall, the most important…\""]}'::jsonb, '{"answer": 2, "explain": "\"On the other hand\" is the scaffold that switches the answer to the second side — the move that makes the discussion balanced."}'::jsonb),
('sport-studies:6-2-extended-response-technique:fib:413950b2', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'fib', 'fib', 1, '{"question": "The first step of a top-band answer is to _____ your point to the scenario you have been given.", "blankOptions": {"B1": ["balanced", "apply", "scenario", "listing"]}}'::jsonb, '{"blanks": {"B1": "apply"}}'::jsonb),
('sport-studies:6-2-extended-response-technique:fib:a5c74f5f', 'sport-studies', 'sport-studies:6-2-extended-response-technique', '6.2 Extended-Response Technique', 'fib', 'fib', 1, '{"question": "The second step is to analyse _____ sides of the issue, not just the side you find easiest.", "blankOptions": {"B1": ["judgement", "both", "listing", "scenario"]}}'::jsonb, '{"blanks": {"B1": "both"}}'::jsonb),
